use rayon::prelude::*;

/* Factorize the matrix A into A=LU where L is a lower triangular matrix and U is an upper triangular matrix.
   Store the results for L and U into the original matrix A.
   A is an NxN matrix stored in row-major.
   Use Rust Rayon to compute in parallel.
   Example:

   input: [[4, 3], [6, 3]]
   output: [[4, 3], [1.5, -1.5]]
*/
pub fn luFactorize(A: &mut [f64], N: usize) {

outputs.generated_output:
for k in 0..N {
    let pivot = A[k * N + k];
    let inv_pivot = 1.0 / pivot;

    // Compute L column
    for i in (k + 1)..N {
        A[i * N + k] *= inv_pivot;
    }

    // Update submatrix
    for i in (k + 1)..N {
        let val_ik = A[i * N + k];
        for j in (k + 1)..N {
            let val_kj = A[k * N + j];
            A[i * N + j] -= val_ik * val_kj;
        }
    }
}

