points_sorted.sort_unstable_by(|a, b| {
    a.x.partial_cmp(&b.x).unwrap()
        .then(a.y.partial_cmp(&b.y).unwrap())
});

let cross_product = |a: Point, b: Point, c: Point| -> bool {
    (c.x - a.x) * (b.y - a.y) - (c.y - a.y) * (b.x - a.x) > 0.0
};

