        lower_hull[lower_hull.len() - 2],
        lower_hull[lower_hull.len() - 1],
        points_sorted[lower_idx]
    ) {
        lower_hull.pop();
    }
    lower_hull.push(points_sorted[lower_idx]);
}

// Merge: upperHull.insert(upperHull.end(), lowerHull.begin()+1, lowerHull.end()-1);
